#define MIN2(a,b) ((a) < (b) ? (a) : (b))

__kernel void dynproc_kernel(__const int iteration,
                             __global const int* gpuWall,
                             __global int* gpuSrc,
                             __global int* gpuDst,
                             __const int cols,
                             __const int rows,
                             __const int startStep,
                             __const int borderCols,
                             __const int HALO,
                             __local int* prev,
                             __local int* result,
                             __global int* outputBuffer)
{
    size_t gid = get_global_id(0);
    if (gid != 0)
        return;

    (void)rows;
    (void)borderCols;
    (void)HALO;
    (void)prev;
    (void)result;
    (void)outputBuffer;

    __global int* bufA = gpuSrc;
    __global int* bufB = gpuDst;

    for (int s = 0; s < iteration; ++s) {
        __global int* in  = (s & 1) ? bufB : bufA;
        __global int* out = (s & 1) ? bufA : bufB;

        int wallOffset = (startStep + s) * cols;

        for (int n = 0; n < cols; ++n) {
            int minv = in[n];
            if (n > 0)
                minv = MIN2(minv, in[n - 1]);
            if (n < cols - 1)
                minv = MIN2(minv, in[n + 1]);
            out[n] = gpuWall[wallOffset + n] + minv;
        }
    }

    if ((iteration & 1) == 0) {
        for (int n = 0; n < cols; ++n) {
            gpuDst[n] = gpuSrc[n];
        }
    }
}
